function OperatorStatusPill({
  t,
  status,
  active = false,
  size = "sm",
  onClick,
}: {
  t: CanvasHostTheme;
  status: (typeof OPERATOR_STATUSES)[number];
  active?: boolean;
  size?: "sm" | "md";
  onClick?: () => void;
}): JSX.Element {
  const shade = operatorStatusShade(t, status.shadeKey)[active ? "active" : "inactive"];
  return (
    <button
      type="button"
      aria-pressed={active}
      onClick={onClick}
      style={{
        fontFamily: "inherit",
        fontSize: size === "sm" ? 10 : 12,
        lineHeight: 1.25,
        padding: size === "sm" ? "1px 6px 1px 5px" : "4px 10px 4px 8px",
        borderRadius: 9999,
        cursor: onClick ? "pointer" : "default",
        border: `1px solid ${shade.border}`,
        borderLeft: size === "sm" ? `2px solid ${shade.borderLeft}` : `3px solid ${shade.borderLeft}`,
        background: shade.background,
        color: shade.color,
        fontWeight: active ? 600 : 500,
        whiteSpace: "nowrap",
        flexShrink: 0,
      }}
    >
      {status.label}
    </button>
  );
}
