function windowControlBtn(theme: CanvasHostTheme): CSSProperties {
  return {
    width: 36,
    height: 32,
    border: "none",
    background: "transparent",
    color: theme.text.secondary,
    fontSize: 12,
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    padding: 0,
  };
}

function WindowTitleBarControls({
  theme,
  onMinimize,
  onMaximize,
  onClose,
  maximized,
  light,
}: {
  theme: CanvasHostTheme;
  onMinimize?: () => void;
  onMaximize?: () => void;
  onClose?: () => void;
  maximized?: boolean;
  light?: boolean;
}): JSX.Element {
  const btn = {
    ...windowControlBtn(theme),
    color: light ? theme.text.onAccent : theme.text.secondary,
  };
  return (
    <div style={{ position: "absolute", top: 0, right: 0, display: "flex", zIndex: 10 }}>
      <button type="button" title="Свернуть" style={btn} onClick={onMinimize}>
        ─
      </button>
      <button type="button" title={maximized ? "Восстановить" : "Развернуть"} style={btn} onClick={onMaximize}>
        {maximized ? "❐" : "□"}
      </button>
      <button type="button" title="Закрыть" style={btn} onClick={onClose}>
        ×
      </button>
    </div>
  );
}

function MockupWindowFrame({
  t,
  scheme,
  title,
  subtitle,
  stateKey,
  children,
  bodyPadding = 16,
  minHeight = 420,
}: {
  t: CanvasHostTheme;
  scheme?: SchemePalette;
  title: string;
  subtitle?: string;
  stateKey: string;
  children: ReactNode;
  bodyPadding?: number;
  minHeight?: number;
}): JSX.Element {
  const [maximized, setMaximized] = useCanvasState(`${stateKey}Maximized`, false);
  const [open, setOpen] = useCanvasState(`${stateKey}Open`, true);

  if (!open) {
    return (
      <Button variant="secondary" onClick={() => setOpen(true)}>
        Открыть окно · {title}
      </Button>
    );
  }

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        minHeight: maximized ? minHeight + 100 : minHeight,
        ...panelStyle(t, { borderRadius: RADIUS_MD, overflow: "hidden" }),
      }}
    >
      <div
        style={{
          position: "relative",
          padding: "10px 16px",
          paddingRight: WINDOW_CONTROLS_WIDTH,
          borderBottom: `1px solid ${t.stroke.secondary}`,
          background: scheme?.headerBg ?? t.fill.tertiary,
        }}
      >
        <Text weight="semibold">{title}</Text>
        {subtitle ? (
          <Text style={{ fontSize: 11, color: t.text.secondary, marginTop: 2 }}>{subtitle}</Text>
        ) : null}
        <WindowTitleBarControls
          theme={t}
          onMinimize={() => setOpen(false)}
          onMaximize={() => setMaximized(!maximized)}
          onClose={() => setOpen(false)}
          maximized={maximized}
        />
      </div>
      <div style={{ padding: bodyPadding, flex: 1 }}>{children}</div>
    </div>
  );
}

