function WidgetMockup({
  t,
  view,
  onViewChange,
  draft,
  onDraftChange,
}: {
  t: CanvasHostTheme;
  view: WidgetView;
  onViewChange: (next: WidgetView) => void;
  draft: string;
  onDraftChange: (next: string) => void;
}): JSX.Element {
  const wp = WIDGET_PALETTE;
  const [widgetMaximized, setWidgetMaximized] = useCanvasState("onlineChatWidgetMaximized", false);
  const [widgetOpen, setWidgetOpen] = useCanvasState("onlineChatWidgetOpen", true);
  const [showTopicOnForm] = useCanvasState("onlineChatWidgetShowTopic", false);
  const [welcomeMessage] = useCanvasState("onlineChatWidgetWelcome", "Здравствуйте! Чем можем помочь?");
  const [farewellMessage] = useCanvasState(
    "onlineChatWidgetFarewell",
    "Спасибо за обращение! Диалог завершён.",
  );
  const [operatorsOnline] = useCanvasState("onlineChatWidgetOperatorsOnline", true);

  const windowControls = {
    onMinimize: () => setWidgetOpen(false),
    onMaximize: () => setWidgetMaximized(!widgetMaximized),
    onClose: () => setWidgetOpen(false),
    maximized: widgetMaximized,
  };

  return (
    <Stack style={{ gap: 12, alignItems: "center" }}>
      <Row style={{ gap: 6, flexWrap: "wrap" }}>
        <Pill active={view === "prechat"} onClick={() => onViewChange("prechat")}>
          Форма входа
        </Pill>
        <Pill active={view === "chat"} onClick={() => onViewChange("chat")}>
          Диалог
        </Pill>
        <Pill active={view === "postchat"} onClick={() => onViewChange("postchat")}>
          После диалога
        </Pill>
        <Pill active={view === "fab"} onClick={() => onViewChange("fab")}>
          FAB
        </Pill>
      </Row>

      {view === "fab" && (
        <Stack style={{ alignItems: "flex-end", gap: 8, width: WIDGET_WIDTH, padding: "24px 0" }}>
          <div
            style={{
              width: 60,
              height: 60,
              borderRadius: 30,
              background: wp.fabBg,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              position: "relative",
              overflow: "hidden",
            }}
          >
            <BankLogoMark size={44} />
            <span
              style={{
                position: "absolute",
                top: -2,
                right: -2,
                minWidth: 18,
                height: 18,
                borderRadius: 9,
                padding: "0 5px",
                background: wp.fabBadge,
                color: "#fff",
                fontSize: 10,
                fontWeight: 600,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              1
            </span>
          </div>
        </Stack>
      )}

      {view === "prechat" && widgetOpen && (
        <div style={widgetPanelStyle(t, widgetMaximized)}>
          <WidgetHeader t={t} wp={wp} variant="brand" subtitle="Беларусбанк" {...windowControls} />
          <div style={{ padding: 20, display: "flex", flexDirection: "column", gap: 16, background: wp.chatBg }}>
            <Text style={{ fontSize: 14, lineHeight: 1.45 }}>{welcomeMessage}</Text>
            {showTopicOnForm ? (
              <div>
                <Text style={{ fontSize: 12, fontWeight: 600, marginBottom: 6 }}>Тема обращения</Text>
                <SelectMock t={t} value="Карты и счета" />
              </div>
            ) : null}
            <Grid columns={2} style={{ gap: 12 }}>
              <div>
                <Text style={{ fontSize: 12, fontWeight: 600, marginBottom: 6 }}>Имя</Text>
                <TextInput placeholder="Анна" />
              </div>
              <div>
                <Text style={{ fontSize: 12, fontWeight: 600, marginBottom: 6 }}>Телефон</Text>
                <TextInput placeholder="+375 29 123-45-67" />
              </div>
            </Grid>
            <WidgetPrimaryButton wp={wp} style={{ width: "100%" }}>
              Начать чат
            </WidgetPrimaryButton>
          </div>
          <div
            style={{
              padding: "12px 20px",
              borderTop: `1px solid ${wp.clientBubbleBorder}`,
              background: wp.footerBg,
            }}
          >
            {operatorsOnline ? (
              <span
                style={{
                  fontSize: 11,
                  fontWeight: 600,
                  color: wp.accentMuted,
                  background: wp.primaryWeak,
                  padding: "4px 10px",
                  borderRadius: 10,
                  display: "inline-block",
                }}
              >
                Операторы онлайн
              </span>
            ) : (
              <span
                style={{
                  fontSize: 11,
                  fontWeight: 500,
                  color: t.text.secondary,
                  padding: "4px 10px",
                  borderRadius: 10,
                  display: "inline-block",
                }}
              >
                Оставьте сообщение — ответим позже
              </span>
            )}
          </div>
        </div>
      )}

      {view === "prechat" && !widgetOpen && (
        <Button variant="secondary" onClick={() => setWidgetOpen(true)}>
          Открыть виджет
        </Button>
      )}

      {view === "chat" && widgetOpen && (
        <div style={widgetPanelStyle(t, widgetMaximized)}>
          <WidgetHeader t={t} wp={wp} variant="neutral" subtitle="Беларусбанк" {...windowControls} />
          <WidgetOperatorStrip t={t} wp={wp} name="Мария Соколова" initials="МС" status="Оператор поддержки" />
          <div
            style={{
              padding: 16,
              minHeight: 260,
              display: "flex",
              flexDirection: "column",
              gap: 12,
              background: wp.chatBg,
            }}
          >
            <WidgetMessageBubble
              t={t}
              wp={wp}
              side="system"
              text="Мария подключилась к диалогу"
            />
            <WidgetMessageBubble
              t={t}
              wp={wp}
              side="operator"
              label="Мария"
              avatarInitials="МС"
              text="Здравствуйте! Уточните, пожалуйста, тип карты и последние четыре цифры номера."
              time="10:05"
            />
            <WidgetMessageBubble
              t={t}
              wp={wp}
              side="client"
              label="Вы"
              avatarInitials="АК"
              text="Дебетовая «Моя карта», окончание 4821."
              time="10:06"
            />
            <WidgetTypingIndicator t={t} wp={wp} />
          </div>
          <WidgetComposer t={t} wp={wp} draft={draft} onDraftChange={onDraftChange} />
        </div>
      )}

      {view === "postchat" && widgetOpen && (
        <div style={widgetPanelStyle(t, widgetMaximized)}>
          <WidgetHeader t={t} wp={wp} variant="neutral" subtitle="Диалог завершён" {...windowControls} />
          <WidgetPostchatContent t={t} wp={wp} farewellMessage={farewellMessage} />
        </div>
      )}

      {view === "postchat" && !widgetOpen && (
        <Button variant="secondary" onClick={() => setWidgetOpen(true)}>
          Открыть виджет
        </Button>
      )}

      {view === "chat" && !widgetOpen && (
        <Button variant="secondary" onClick={() => setWidgetOpen(true)}>
          Открыть виджет
        </Button>
      )}
    </Stack>
  );
}

